// Service Worker for AquaMeter PWA
// This file is auto-generated by vite-plugin-pwa
// Manual SW for offline support

const CACHE_NAME = 'aquameter-v2'
const STATIC_ASSETS = [
  '/',
  '/index.html',
  '/manifest.webmanifest',
]

// Install
self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => {
      return cache.addAll(STATIC_ASSETS)
    })
  )
  self.skipWaiting()
})

// Activate
self.addEventListener('activate', event => {
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
    )
  )
  self.clients.claim()
})

// Fetch - Network first, fallback to cache
self.addEventListener('fetch', event => {
  const { request } = event
  const url = new URL(request.url)

  // Skip non-GET and API calls
  if (request.method !== 'GET') return
  if (url.pathname.startsWith('/api')) return

  event.respondWith(
    fetch(request)
      .then(response => {
        // Cache successful responses
        if (response.ok) {
          const clone = response.clone()
          caches.open(CACHE_NAME).then(cache => cache.put(request, clone))
        }
        return response
      })
      .catch(() => caches.match(request))
  )
})

// Background Sync for offline readings
self.addEventListener('sync', event => {
  if (event.tag === 'sync-readings') {
    event.waitUntil(syncPendingReadings())
  }
})

async function syncPendingReadings() {
  const cache = await caches.open('pending-readings')
  const keys = await cache.keys()
  for (const key of keys) {
    const response = await cache.match(key)
    const data = await response.json()
    try {
      await fetch('/api/readings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      })
      await cache.delete(key)
    } catch {
      // Will retry on next sync
    }
  }
}
